INSERT INTO blog_posts (title_ru, title_en, slug, excerpt_ru, excerpt_en, body_ru, body_en, cover_image, tags, published_at, featured, status, sort_order, created_at, updated_at) VALUES
('Новый подход к backend-практике', 'A fresh approach to backend practice', 'backend-practice', 'Практика backend должна быть понятной, документированной и применимой вне учебного шага.', 'Backend practice should be clear, documented, and applicable beyond the study phase.', 'В этой записи я рассказываю, почему backend-проекты выигрывают от строгой структуры данных, понятных API и реалистичных сценариев использования.', 'In this post I explain why backend projects benefit from strict data structure, clear APIs, and realistic usage scenarios.', 'assets/img/blog-backend.svg', 'backend,api,practice', NOW(), 1, 'published', 1, NOW(), NOW()),
('API и UX developer experience', 'API and developer experience', 'api-developer-experience', 'Хороший API — это не только данные, но и удобство работы с ним для разработчика.', 'A good API is not only about data but also developer usability.', 'Хороший API учитывает ошибки, валидацию, документацию и понятное поведение при нестандартных запросах.', 'A good API takes errors, validation, docs, and sensible behavior for edge requests into account.', 'assets/img/blog-api.svg', 'api,developer,ux', NOW(), 0, 'published', 2, NOW(), NOW());

INSERT INTO skills (group_ru, group_en, title_ru, title_en, description_ru, description_en, skill_level, icon, sort_order, status, created_at, updated_at) VALUES
('Языки', 'Languages', 'Go', 'Go', 'Использую Go для API, учебных сервисов и небольших backend-инструментов, где важны ясность и спокойная структура.', 'I use Go for APIs, study services, and smaller backend tools where clarity and structure matter.', 'Core', 'go', 1, 'published', NOW(), NOW()),
('Языки', 'Languages', 'PHP', 'PHP', 'Использую PHP для production-minded веб-систем, форм, админ-панелей и серверной логики.', 'I use PHP for production-minded web systems, forms, admin panels, and server-side logic.', 'Core', 'php', 2, 'published', NOW(), NOW()),
('Языки', 'Languages', 'Python', 'Python', 'Применяю Python для утилит, автоматизации и небольших технических сценариев.', 'I use Python for utilities, automation, and smaller technical workflows.', 'Applied', 'py', 3, 'published', NOW(), NOW()),
('Backend', 'Backend', 'REST API', 'REST API', 'Проектирую и реализую API с понятной структурой, предсказуемым поведением и аккуратной обработкой запросов.', 'I build REST APIs with clear structure, predictable behavior, and careful request handling.', 'Core', 'api', 4, 'published', NOW(), NOW()),
('Backend', 'Backend', 'HTTP', 'HTTP', 'Понимаю клиент-серверную модель, маршрутизацию, обработку запросов и взаимодействие между слоями приложения.', 'Comfortable with client-server flow, routing, request handling, and interaction between application layers.', 'Core', 'http', 5, 'published', NOW(), NOW()),
('Backend', 'Backend', 'SQL', 'SQL', 'Работаю с SQL-запросами, выборками, фильтрацией и прикладной логикой данных.', 'I work with SQL queries, filtering, data retrieval, and practical data logic.', 'Core', 'sql', 6, 'published', NOW(), NOW()),
('Базы данных', 'Databases', 'PostgreSQL', 'PostgreSQL', 'Использую PostgreSQL в backend-кейсах, где важны структура данных, фильтрация и надежная работа с сущностями.', 'I use PostgreSQL in backend case studies where data structure, filtering, and reliable entity handling matter.', 'Core', 'pg', 7, 'published', NOW(), NOW()),
('Базы данных', 'Databases', 'MySQL', 'MySQL', 'Использую MySQL в веб-проектах, CRUD-сценариях, настройках сайта и админских интерфейсах.', 'I use MySQL in web projects, CRUD scenarios, site settings, and admin-oriented interfaces.', 'Core', 'my', 8, 'published', NOW(), NOW()),
('Базы данных', 'Databases', 'Redis', 'Redis', 'Работаю с Redis в практических backend-сценариях, где нужен быстрый доступ к служебным данным.', 'I use Redis in practical backend flows where fast access to supporting data is useful.', 'Applied', 'rd', 9, 'published', NOW(), NOW()),
('Инструменты', 'Tools', 'Docker', 'Docker', 'Использую Docker для упаковки и повторяемого запуска учебных и прикладных проектов.', 'I use Docker to package and run study and applied projects in a repeatable way.', 'Applied', 'dk', 10, 'published', NOW(), NOW()),
('Инструменты', 'Tools', 'Git', 'Git', 'Использую Git как базовый инструмент контроля изменений и аккуратной итеративной разработки.', 'I use Git as the standard tool for version control and steady iterative development.', 'Core', 'git', 11, 'published', NOW(), NOW()),
('Инженерный подход', 'Engineering approach', 'Поддерживаемость', 'Maintainability', 'Стараюсь собирать решения так, чтобы их было легче читать, поддерживать и развивать дальше.', 'I aim to build solutions that stay easier to read, maintain, and extend over time.', 'Approach', 'mt', 12, 'published', NOW(), NOW()),
('Инженерный подход', 'Engineering approach', 'Практичность решения', 'Practical problem solving', 'Фокусируюсь на логике, пользе и рабочем результате, а не на лишней сложности.', 'I focus on logic, usefulness, and working outcomes instead of unnecessary complexity.', 'Approach', 'ps', 13, 'published', NOW(), NOW());

INSERT INTO services (title_ru, title_en, description_ru, description_en, cta_ru, cta_en, accent, sort_order, status, created_at, updated_at) VALUES
('Backend-разработка', 'Backend development', 'Серверная логика, API, бизнес-правила, обработчики, данные и прикладные сценарии для web-систем.', 'Server-side logic, APIs, business rules, data handling, and practical workflows for web systems.', 'API, логика, интеграции', 'APIs, logic, integrations', '#93F5B2', 1, 'published', NOW(), NOW()),
('API и интеграции', 'API development and integrations', 'REST API, внешние и внутренние интеграции, соединение сервисов, форм и клиентских интерфейсов.', 'REST APIs, internal and external integrations, and the connection between services, forms, and client-facing interfaces.', 'Связанные backend-сценарии', 'Connected backend flows', '#7CC8FF', 2, 'published', NOW(), NOW()),
('Сайты и admin-панели', 'Websites and admin panels', 'Бизнес-сайты, панели управления, CRUD-сценарии и внутренние интерфейсы с понятной структурой.', 'Business websites, control panels, CRUD workflows, and internal interfaces with clear structure.', 'Сайт + control layer', 'Website + control layer', '#D7FF8E', 3, 'published', NOW(), NOW()),
('Утилиты и автоматизация', 'Automation tools and utilities', 'Небольшие решения на Go и Python для автоматизации действий, работы с данными и внутренних процессов.', 'Small Go and Python solutions for workflow automation, data handling, and internal processes.', 'Практичные внутренние инструменты', 'Practical internal tooling', '#A7D8FF', 4, 'published', NOW(), NOW()),
('Data-driven веб-решения', 'Data-driven web solutions', 'Веб-продукты и backend-сценарии, где важны формы, фильтры, статусы, данные и аккуратная логика.', 'Web products and backend workflows where forms, filtering, statuses, data, and careful logic matter.', 'Данные, фильтры, логика', 'Data, filters, logic', '#C9F4B8', 5, 'published', NOW(), NOW());

INSERT INTO faqs (question_ru, question_en, answer_ru, answer_en, sort_order, status, created_at, updated_at) VALUES
('С какими технологиями вы работаете?', 'What technologies do you work with?', 'Основной публичный стек: Go, PHP, Python, PostgreSQL, MySQL, Redis, REST API, HTTP, SQL, Docker и Git.', 'My public stack includes Go, PHP, Python, PostgreSQL, MySQL, Redis, REST API, HTTP, SQL, Docker, and Git.', 1, 'published', NOW(), NOW()),
('Вы работаете только с backend?', 'Do you work only on backend?', 'Основной фокус у меня на backend, API и серверной логике, но при необходимости я также собираю связанный web-интерфейс и административную часть.', 'My main focus is backend, APIs, and server-side logic, but I can also build the connected web interface and admin layer when needed.', 2, 'published', NOW(), NOW()),
('Можно ли собрать сайт с админ-панелью?', 'Can you build a website with an admin panel?', 'Да. Я могу собрать сайт, формы, CRUD-логику, скрытую admin-панель и связанный backend-слой как единое решение.', 'Yes. I can build the site, forms, CRUD logic, a hidden admin panel, and the connected backend layer as one solution.', 3, 'published', NOW(), NOW()),
('Открыты ли вы к проектной работе?', 'Are you open to project work?', 'Да. Открыт к сотрудничеству, проектной работе и задачам, где важны backend, API, web-системы и прикладная логика.', 'Yes. I am open to collaboration and project work where backend, APIs, web systems, and practical logic matter.', 4, 'published', NOW(), NOW()),
('Как лучше связаться с вами?', 'What is the best way to contact you?', 'Через форму на сайте, по email, по телефону или в Telegram: @Fakhriddin_dev.', 'Through the website form, by email, by phone, or on Telegram: @Fakhriddin_dev.', 5, 'published', NOW(), NOW());

